<?php
namespace App\Console\Commands;
use App\Models\SecurityReviewerAccess;use Illuminate\Console\Command;
class ReviewerAccessExpiringSoonCommand extends Command{protected $signature='security:reviewer-access-expiring-soon {--days=7} {--notify} {--dry-run}';protected $description='Report delegated reviewer access expiring soon';public function handle():int{$days=max(1,(int)$this->option('days'));$items=SecurityReviewerAccess::where('status','active')->whereBetween('expires_at',[now(),now()->addDays($days)])->get();$this->info("Reviewer accesses expiring within {$days} days: {$items->count()}");if(!$this->option('dry-run'))foreach($items as $a){$today=now()->toDateString();if(!$a->events()->where('event_type','expiring_soon_noted')->whereDate('created_at',$today)->exists())$a->events()->create(['user_id'=>$a->user_id,'event_type'=>'expiring_soon_noted','description'=>"Access expires within {$days} days. Notification delivery is not configured.",'created_at'=>now()]);}return self::SUCCESS;}}
